var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"촌장님…… 저희는 이제 어떻게 되는 걸까요?","JPN":"村長……私たちはどうなるんでしょうか。","ENG":"Chief... What's going to happen to us now?","TWN":"村長……我們現在該怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"걱정 말게. 지휘관님 지시대로만 기다리고 있으면 괜찮을 걸세.","JPN":"心配するでない。指揮官の指示どおり待っていれば大丈夫じゃ。","ENG":"Don't worry. We will be all right if we wait as Commander ordered.","TWN":"放心，只要按照指揮官的指示等待就會沒事的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"촌장님도 보셨잖아요. 수비대가 마을 사람들을 침식체라고 쏴 버리는 모습을.","JPN":"村長もご覧になったじゃないですか。守備隊が村人を侵食体だと言って撃ち殺す姿を。","ENG":"But you saw what happened too, didn't you? The guards started shooting at the villagers, calling them C.O.s.","TWN":"村長不是也看到嗎？護衛隊將村民們當成侵蝕體射殺。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L6_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"지휘관님도… 이미 돌아가셨을지도 몰라요.","JPN":"指揮官も……もう亡くなっているかもしれませんよ。","ENG":"Maybe... Commander's dead already...","TWN":"指揮官也許…已經不在人世。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"여기 숨어 있다가 더 위험해질 바엔 지금이라도 우리끼리 도망치는 편이…","JPN":"ここに隠れていてもっと危なくなるくらいなら、今からでも私たちで逃げた方が……","ENG":"It's going be more dangerous hiding out here! Don't you think we should run─","TWN":"躲在這裡只會變得更危險，不如我們趁現在逃跑…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"우리가 살고 싶어서 여기 온 건가?","JPN":"わしらは生きたくてここに来たんじゃったかの？","ENG":"Do you think we're here because we want to live?","TWN":"我們是想活命才來這裡的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"가족들 앞에서 침식체로 변해 날뛰다 비참하게 죽는 것보단…….","JPN":"家族の前で侵食体になって暴れた挙句、惨めに死んでいくよりは……","ENG":"I came here voluntarily because I'd rather die in the hands of the guards...","TWN":"是因爲不想在家人面前變成侵蝕體悲慘死去……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"수비대에게 최후를 맡기는 편이 낫다고 생각해서 제 발로 여기 온 걸세.","JPN":"守備隊に最期を預ける方がましだと、自らの足でここに来たんじゃ。","ENG":"Than turn into a C.O. in front of my family and die a horrible death.","TWN":"於是決定將生命的最後交給護衛隊，才自願來到這裡的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그런 우리가 수비대를 믿지 않으면 살아남는다고 무슨 의미가 있겠나?","JPN":"そんなわしらが守備隊を信じないで、生き残ることに何の意味があるというんじゃ。","ENG":"Also, what would be the point of living if we don’t trust those who are trying to protect us?","TWN":"如果我們不相信護衛隊，就算活下來又有什麼意義？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"살아 계실까요?","JPN":"生きていらっしゃるでしょうか？","ENG":"Do you think he's still alive?","TWN":"他還活著嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그러길 바라야지.","JPN":"そう望むしかない。","ENG":"I can only hope.","TWN":"希望如此。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"무… 무슨 소리죠? 뭔가 이쪽으로 오는 것 같은데?","JPN":"な……何の音でしょう？　こちらに向かって来てるようですけど。","ENG":"D-did you hear that? Something's coming this way!","TWN":"什… 什麼聲音？好像有什麼東西往這邊靠近？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"쉿, 조용.","JPN":"しっ、静かに。","ENG":"Hush, everyone!","TWN":"噓，安靜。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"지, 지휘관님!","JPN":"し、指揮官！","ENG":"C-Commander!","TWN":"指…指揮官！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"대원들이 밖에서 대기 중이다. 대피로를 확보해 뒀으니 모두 밖으로 나오도록.","JPN":"隊員が外で待機している。逃げ道を確保しておいたから、みんな外に出てきてくれ。","ENG":"The troops are waiting outside. We've secured the evacuation route, so please follow us.","TWN":"隊員們正在外面等候，我已經安排好逃生路線，大家都出來吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"죄송합니다만, 지휘관님.","JPN":"すみませんが、指揮官。","ENG":"Commander, if you may...","TWN":"對不起，指揮官。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"저희 눈에 보이는 지휘관님이 헛것이 아니라는 걸 이 늙은이에게 확인시켜 주시겠습니까?","JPN":"わしらの目の前にいる指揮官が本物であるということを、この老人に確認させてくださらんかの？","ENG":"Could you please assure this old man that the commander in front of him is not a figment of his imagination?","TWN":"你可以讓我這個老頭子確認一下，眼前的這位指揮官是真的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내가 처음 이곳 외성에 왔던 날. 촌장은 날 배반자라며 재판에 세우려 했었지.","JPN":"私が初めてこの外郭に来た日。村長は私を裏切り者として裁判にかけようとした。","ENG":"When I first arrived here, you tried to put me on trial as a traitor of this country.","TWN":"我第一次來外城的那天，村長說我是叛徒，想要送我去受審。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 다음날 아침, 침대 옆에는 찐 감자가 있더군. 아주 맛있었어.","JPN":"だが次の日の朝、ベッドの横にはふかしたジャガイモがあったな。とてもおいしかった。","ENG":"But the very next day, I found a delicious boiled potato next to my bed.","TWN":"但是隔天早上，床邊有蒸馬鈴薯，非常好吃。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"나중에 피터에게 들었지만, 그렇게 흐물흐물해질 만큼 감자를 찌는 건 촌장뿐이라더군.","JPN":"後でピーターから聞いたんだが、そんなにやわらかくなるまでジャガイモをふかすのは村長だけだそうだな。","ENG":"It was only later when I heard from Peter that the only person who boils potatoes until they're mushy is you, Chief O'Neil.","TWN":"後來聽彼得說，能把馬鈴薯蒸得那麼軟的人就只有村長而已。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"난 아직 그 때의 빚을 갚지 못했다.","JPN":"私はまだその時の借りを返せないでいる。","ENG":"I still owe you for that.","TWN":"我還沒有還那時候的人情呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"오늘 그 기회를 주지 않겠나? 모두 안전하게 빠져나갈 수 있도록 도와 주지.","JPN":"今日、その機会をくれないか？　みんなが無事に抜け出せるようにサポートする。","ENG":"Will you give me a chance to make it even? I'll make sure that everyone gets out of here safely.","TWN":"今天可以給我個機會嗎？我會幫助你們安全地逃出去。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_NULL_ADULT","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"다들 서두르게. 아이들부터 먼저 챙기고.","JPN":"みんな、急ぐのじゃ。子供たちから先に。","ENG":"Everyone, let's hurry. Get the children first.","TWN":"大家抓緊時間，顧好孩子。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_NULL_ADULT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"네… 네!","JPN":"は……はい！","ENG":"Yes, sir!","TWN":"好…好的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_NULL_ADULT","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"와 주셔서 감사합니다, 지휘관님.","JPN":"来てくださってありがとうございます、指揮官。","ENG":"Thank you for coming, Commander.","TWN":"謝謝你來找我們，指揮官。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"지휘관님이 계신 1년 동안, 저희가 더 많은 빚을 졌습니다.","JPN":"指揮官がいらしてからの1年間、借りならわしらの方がずっと多い。","ENG":"For the past year that you've stayed with us, we owe you more than you know.","TWN":"指揮官在這裡的一年，我們反而欠你比較多呢。   "},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"모두 이쪽 샛길로 오세요. 저희가 엄호하겠습니다.","JPN":"みなさん、こっちの抜け道に来てください。僕たちが援護します。","ENG":"Everyone, come over here. We'll cover you.","TWN":"大家請走這邊的小路，我們掩護大家。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"비탈이 미끄럽습니다. 조심하십시오.","JPN":"斜面が滑りやすくなっています。気をつけて。","ENG":"Be careful. The slope is slippery.","TWN":"斜坡很滑，請小心。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"세 사람씩 천천히. 질서 없이 움직이면 놈들의 눈에 띈다.","JPN":"三人ずつ、ゆっくり。無秩序に動くとやつらの目を引く。","ENG":"Make groups of three and move slowly. They'll notice us if we move disorderly.","TWN":"三個人一組，慢慢來。如果亂動的話，就會被它們發現。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"……모두 빠져나왔습니다. 제가 마지막입니다.","JPN":"……みんな出ました。わしが最後です。","ENG":"...Everyone's been evacuated safely. I'm the last.","TWN":"……大家都逃出來了，我是最後一個。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"협조해 줘서 고맙다. 이제부터 여긴 우리 수비대가 맡지.","JPN":"協力に感謝する。これからここは我々守備隊が引き受けよう。","ENG":"Thank you for your help. I leave the rest to you, Border Guards.","TWN":"謝謝你們的配合，從現在開始，這裡就由我們護衛隊負責。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장교님께선 주민들과 함께 가십시오. 지리에 익숙한 사람들이니 숲에서 길을 잃진 않을 겁니다.","JPN":"将校は住民と一緒に移動してください。土地勘があるので、森で迷わないはずです。","ENG":"Officer Rashford, go with the villagers. They know their way around the forest, so you won't get lost.","TWN":"軍官和居民們一起走吧，他們都是熟悉地理的人，不會在森林裡迷路的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……알겠다. 뒤는 맡기마.","JPN":"……わかった。あとは頼む。","ENG":"...Okay. I leave the rest to you.","TWN":"……好，那後面就交給你了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"다들…… 부디… 살아남으십시오.","JPN":"みなさん……どうか……生き残ってください。","ENG":"Please... Come back alive.","TWN":"請大家…千萬…要活著。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"약속하지.","JPN":"約束する。","ENG":"I promise.","TWN":"我答應你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"망할. 벌써 들켰나?","JPN":"くそ。もうバレたか？","ENG":"Dammit! Did it find us already?","TWN":"糟糕，這麼快就被發現了？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"전방에 대형 침식체입니다!","JPN":"前方に大型の侵食体です！","ENG":"Large C.O. in front!","TWN":"前方有大型侵蝕體！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"1종 다수 확인! 양쪽으로 우회해서 옵니다! 빨라요!","JPN":"多数の第1種を確認！　両方から迂回してきます！　速いですよ！","ENG":"Multiple Category 1s confirmed! They're fast! And coming in at our flanks!","TWN":"確認有多個1類！從二邊繞過來！速度很快！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"말도 안 돼. 침식체가 우회 공격이라고요?","JPN":"あり得ねえ。侵食体が迂回攻撃だと？","ENG":"Impossible! C.O.s know how to flank?","TWN":"會不會太誇張，侵蝕體還會繞道攻擊？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"당황하지 마라!","JPN":"慌てるな！","ENG":"Don't panic!","TWN":"別慌！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침착하게 좌측부터 공략해! 전방의 대형은 나와 1번 분대가 맡겠다!","JPN":"落ち着いて左側から攻めろ！　前方の大型は私と1番分隊が処理する！","ENG":"We start clearing from the left! Squad 1 and I will take on the big one in front!","TWN":"冷靜一點，從左邊開始攻擊！前方的大型由我和1號分隊負責！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"우측에서 오는 놈들은 어떡합니까?","JPN":"右側からのやつらはどうしますか？","ENG":"What about the ones coming from the right?","TWN":"那右邊來的傢伙怎麼辦？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"우측은 내가 맡지.","JPN":"右側は私がやる。","ENG":"I'll handle them.","TWN":"右邊由我負責吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"대, 대장님?!","JPN":"た、隊長！？","ENG":"C-captain!!","TWN":"隊…隊長？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"대장님! 살아 계셨습니까?","JPN":"隊長！　生きてたんですか？","ENG":"Captain! You're alive!","TWN":"隊長！你還活著？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"지휘관님께서 그림자에게 당했다고 하셨는데…","JPN":"指揮官はシャドウにやられたって……","ENG":"The Commander said that you were attacked by a Shadow...","TWN":"指揮官你已經遇害…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당하긴 했지만, 아직 살아 있어.","JPN":"やられたけど、まだ生きてる。","ENG":"Yes, but I'm not dead yet.","TWN":"是有被打中，但還活著。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"피를 좀 많이 흘려서 잠깐 잠들었을 뿐이야.","JPN":"血を流しすぎてちょっと眠っていただけだ。","ENG":"I just fainted due to losing some blood.","TWN":"只是流太多血，暫時睡著而已。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"미안하군. 장교님을 구하는 데 집중하느라 미처 살피지 못했어.","JPN":"すまない。将校を助けるのに集中していて確認もできかった。","ENG":"Sorry about that. I was too focused on Officer Rashford to notice.","TWN":"對不起，我忙著救軍官，來不及顧到你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"괜찮아. 거기서 나에게 눈길 줬다가 당했으면 용서하지 않았을 테니까.","JPN":"問題ない。そこで私に目をやってやられていたら許さなかったはずだから。","ENG":"No worries. I would've never forgiven you if you went looking for me and got beat up yourself.","TWN":"沒關係，如果你因為要顧我而受到攻擊，那我不會原諒你的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"힘들어 보이는데, 괜찮겠나?","JPN":"辛そうに見えるが、大丈夫なのか？","ENG":"You look tired. You okay?","TWN":"你看起來很累的樣子，還好嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"나 없이 막을 수 있으면 좀 쉴까?","JPN":"私なしで食い止められると言うなら休んでもいいけど？","ENG":"Then should I take a rest and leave it to you?","TWN":"沒有我也行的話，那我休息一下吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"무리만 하지 말도록.","JPN":"無理だけはするな。","ENG":"Just don't strain yourself.","TWN":"不要太勉強自己。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"어련하시겠어.","JPN":"はいはい。","ENG":"You'd like that, wouldn't you?","TWN":"你說的對。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"대장님께서 전선으로 복귀하셨다!","JPN":"隊長が戦線に復帰した！","ENG":"Captain's gone back to the frontlines!","TWN":"隊長回來了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L2_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"이길 수 있어! 절대 물러서지 마! 끝까지 싸워라!","JPN":"勝てる！　絶対に引くな！　最後まで戦え！","ENG":"We can win this! Don't retreat! Fight 'til the end!","TWN":"我們會贏的！絕對不要退縮，戰鬥到底！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};